    }
    if (node.kind == @as(c_uint, @bitCast(CExprKind_ck_str_lit))) {
        return node.str_val;
    }
    if (node.kind == @as(c_uint, @bitCast(CExprKind_ck_char_lit))) {
        return node.char_val;
    }
    if (node.kind == @as(c_uint, @bitCast(CExprKind_ck_bool_lit))) {
