}
pub export fn CPrinter_print_else_chain(arg_self: [*c]CPrinter, arg_else_idx: i64) void {
    var self = arg_self;
    _ = &self;
    var else_idx = arg_else_idx;
    _ = &else_idx;
    var else_node: CStmtNode = ArrayList_CStmtNode_get(self.*.stmt_pool, else_idx);
    _ = &else_node;
    if (else_node.kind == @as(c_uint, @bitCast(CStmtKind_cs_if))) {
        var cond: [*c]const u8 = CPrinter_print_expr(self, else_node.if_cond);
        _ = &cond;
        CCodeBuilder_append_to_last_line(self.*.builder, concatAlloc(" else if ", CPrinter_format_cond(self, cond)));
        CPrinter_print_stmt(self, else_node.if_then);
        if (else_node.if_else >= @as(c_longlong, 0)) {
            CPrinter_print_else_chain(self, else_node.if_else);
        }
    } else {
        CCodeBuilder_append_to_last_line(self.*.builder, " else");
        CPrinter_print_stmt(self, else_idx);
    }
}
pub export fn CPrinter_print_stmt(arg_self: [*c]CPrinter, arg_idx: i64) void {
    var self = arg_self;
    _ = &self;
    var idx = arg_idx;
    _ = &idx;
    if (idx < @as(c_longlong, 0)) {
        return;
    }
    var node: CStmtNode = ArrayList_CStmtNode_get(self.*.stmt_pool, idx);
    _ = &node;
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_block))) {
