        var i: i64 = 0;
        _ = &i;
        while (i < ArrayList_Int_length(&node.block_stmts)) {
            CPrinter_print_stmt(self, ArrayList_Int_get(&node.block_stmts, i));
            _ = blk: {
                const tmp = i + @as(c_longlong, 1);
                i = tmp;
                break :blk tmp;
            };
        }
        CCodeBuilder_end_block(self.*.builder);
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_expr))) {
        CCodeBuilder_emit_line(self.*.builder, concatAlloc(CPrinter_print_expr(self, node.expr_stmt), ";"));
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_if))) {
        var cond: [*c]const u8 = CPrinter_print_expr(self, node.if_cond);
        _ = &cond;
        CCodeBuilder_emit_line(self.*.builder, concatAlloc("if ", CPrinter_format_cond(self, cond)));
        CPrinter_print_stmt(self, node.if_then);
        if (node.if_else >= @as(c_longlong, 0)) {
            CPrinter_print_else_chain(self, node.if_else);
        }
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_while))) {
        var cond: [*c]const u8 = CPrinter_print_expr(self, node.while_cond);
        _ = &cond;
        CCodeBuilder_emit_line(self.*.builder, concatAlloc("while ", CPrinter_format_cond(self, cond)));
        CPrinter_print_stmt(self, node.while_body);
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_for))) {
        var init: [*c]const u8 = CPrinter_print_expr(self, node.for_init);
        _ = &init;
        var cond: [*c]const u8 = CPrinter_print_expr(self, node.for_cond);
        _ = &cond;
        var inc: [*c]const u8 = CPrinter_print_expr(self, node.for_inc);
        _ = &inc;
        CCodeBuilder_emit_line(self.*.builder, concatAlloc(concatAlloc(concatAlloc(concatAlloc(concatAlloc(concatAlloc("for (", init), "; "), cond), "; "), inc), ")"));
        CPrinter_print_stmt(self, node.for_body);
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_return))) {
