            var val: [*c]const u8 = CPrinter_print_expr(self, node.return_val);
            _ = &val;
            CCodeBuilder_emit_line(self.*.builder, concatAlloc(concatAlloc("return ", val), ";"));
        } else {
            CCodeBuilder_emit_line(self.*.builder, "return;");
        }
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_break))) {
        CCodeBuilder_emit_line(self.*.builder, "break;");
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_continue))) {
        CCodeBuilder_emit_line(self.*.builder, "continue;");
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_var_decl))) {
        var type_str: [*c]const u8 = ctype_to_str(node.var_type);
        _ = &type_str;
        if (node.var_init >= @as(c_longlong, 0)) {
            var init_val: [*c]const u8 = CPrinter_print_expr(self, node.var_init);
            _ = &init_val;
            CCodeBuilder_emit_line(self.*.builder, concatAlloc(concatAlloc(concatAlloc(concatAlloc(concatAlloc(type_str, " "), node.var_name), " = "), init_val), ";"));
        } else {
            CCodeBuilder_emit_line(self.*.builder, concatAlloc(concatAlloc(concatAlloc(type_str, " "), node.var_name), ";"));
        }
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_text))) {
        CCodeBuilder_emit_line(self.*.builder, node.case_val);
    }
    if (node.kind == @as(c_uint, @bitCast(CStmtKind_cs_asm))) {
