    }
}
pub export fn CPrinter_print_decl(arg_self: [*c]CPrinter, arg_decl: CDeclNode) void {
    var self = arg_self;
    _ = &self;
    var decl = arg_decl;
    _ = &decl;
    if (decl.is_typedef) {
        var def_str: [*c]const u8 = ctype_to_str(decl.typedef_def);
