                    const tmp = concatAlloc(params_str, ", ");
                    params_str = tmp;
                    break :blk tmp;
                };
            }
            _ = blk: {
                const tmp = concatAlloc(params_str, ArrayList_Str_get(&decl.func_params, i));
                params_str = tmp;
                break :blk tmp;
            };
