                _ = blk: {
                    const tmp = arg;
                    project_path = tmp;
                    break :blk tmp;
                };
            }
        }
        _ = blk: {
            const tmp = i + @as(c_longlong, 1);
            i = tmp;
            break :blk tmp;
        };
    }
    var src_dir: [*c]const u8 = concatAlloc(project_path, "/src");
    _ = &src_dir;
    if (!mkdir_p(src_dir)) {
        _ = printf("Error: Could not create directory '%s'\n", src_dir);
        return 1;
    }
    if (@as(c_longlong, @bitCast(@as(c_longlong, strcmp(template, "lib")))) == @as(c_longlong, 0)) {
        var main_content: [*c]const u8 = concatAlloc(concatAlloc("// ", project_path), "\n// Library entry point\n\n");
        _ = &main_content;
