            return 1;
        }
    } else {
        var main_content: [*c]const u8 = concatAlloc(concatAlloc(concatAlloc(concatAlloc("// ", project_path), "\n// Imports\nimport std.io.print\n\n// Entry point\n\nfn main() Int {\n    printf(\"Hello! from "), project_path), "\\n\")\n    return 0\n}\n");
        _ = &main_content;
        var write_res: Result_Bool_IoError = write_string(concatAlloc(src_dir, "/main.kai"), main_content);
        _ = &write_res;
        if (write_res.tag != @as(c_longlong, 0)) {
            _ = printf("Error: Could not write main.kai\n");
            return 1;
        }
    }
    _ = printf("Created Kai project at '%s' (template: %s)\n", project_path, template);
